css_variables:
:root {
  --primary: #006C71;
  --primary-foreground: #FFFFFF;
  --secondary: #E0F2F1;
  --accent: #FF7E6B;
  --background: #F9FAFC;
  --foreground: #1E293B;
  --surface: #F1F5F9;
  --muted: #CBD5E1;
  --muted-foreground: #64748B;
  --border: #E2E8F0;
  --destructive: #EF4444;
  --success: #22C55E;
  --warning: #FBBF24;
  --info: #3B82F6;

  --font-heading: 'Urbanist', sans-serif;
  --font-body: 'DM Sans', sans-serif;
  --font-mono: 'Source Code Pro', monospace;

  --radius-sm: 2px;
  --radius-default: 6px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;

  --shadow-default: 0px 2px 4px rgba(0, 0, 0, 0.04), 0px 4px 8px rgba(0, 0, 0, 0.02);
  --shadow-md: 0px 4px 8px rgba(0, 0, 0, 0.06), 0px 8px 16px rgba(0, 0, 0, 0.04);
  --shadow-lg: 0px 8px 16px rgba(0, 0, 0, 0.08), 0px 16px 32px rgba(0, 0, 0, 0.06);
}
